class Solution:
    def radixSort(self, nums: list[int]) -> bool:
        if len(nums) <= 1:
            return True

        max_digit = max(map(len, map(str, nums)))

        exp = 1
        while exp <= max_digit:
            buckets = [[] for _ in range(10)]
            for num in nums:
                digit = int(str(num)[-(exp - 1)])
                buckets[digit].append(num)
            nums.clear()
            for bucket in buckets:
                nums.extend(bucket)
            exp *= 10
        return True

    def main(self):
        nums = [170, 45, 75, 90, 802, 24, 2, 66]
        if self.radixSort(nums):
            print(nums)
        else:
            print('No solution exists')

